import { query, type SDKMessage } from "@anthropic-ai/claude-code";

async function askClaude(prompt: string): Promise<string> {
  let finalText = "";

  for await (const message of query({ prompt })) {
    if (message.type === "result" && !message.is_error) {
      finalText = message.result;
    }
  }

  return finalText;
}

// Usage
const answer = await askClaude("What is the cyclomatic complexity of auth.ts?");
console.log(answer);

import { query } from "@anthropic-ai/claude-code";

for await (const event of query({
  prompt: "Refactor the authentication module",

  // Session options
  resume: "session-uuid-from-previous-run",    // --resume
  // continue: true,                           // --continue (mutually exclusive)

  // Loop control
  maxTurns: 15,                                // --max-turns

  // System prompt additions
  systemPrompt: "You are reviewing production code. Be conservative.",

  // Permission control (never prompt for confirmation)
  allowedTools: ["Read", "Grep", "Glob"],      // only these tools allowed
  // disallowedTools: ["Bash"],                // or denylist specific tools

  // MCP servers to load
  mcpServers: {
    github: {
      command: "npx",
      args: ["-y", "@github/mcp-server"],
      env: { GITHUB_TOKEN: process.env.GITHUB_TOKEN! },
    },
  },

  // Path to claude binary if not on PATH
  claudePath: "/usr/local/bin/claude",

  // Working directory for claude
  cwd: "/workspace/my-project",
})) {
  if (event.type === "assistant") {
    process.stdout.write(event.message.content[0].text ?? "");
  }
}

import { query, type SDKMessage } from "@anthropic-ai/claude-code";

let sessionId: string | undefined;
let totalCost = 0;

for await (const event of query({ prompt: "Add input validation to all API routes" })) {
  switch (event.type) {
    case "assistant":
      // Incremental assistant text (may span multiple events)
      for (const block of event.message.content) {
        if (block.type === "text") process.stdout.write(block.text);
        if (block.type === "tool_use") console.error(`[tool] ${block.name}(${JSON.stringify(block.input)})`);
      }
      break;

    case "tool_result":
      // Tool output — inspect if you want to log tool results
      break;

    case "result":
      // Terminal event — always present at the end
      sessionId = event.session_id;
      totalCost = event.cost_usd ?? 0;
      if (event.is_error) {
        console.error("Claude returned an error:", event.result);
        process.exit(1);
      }
      break;
  }
}

console.log(`\nSession: ${sessionId}  Cost: $${totalCost.toFixed(4)}`);

#!/usr/bin/env npx tsx
// review.ts — usage: ./review.ts <file>
import { query } from "@anthropic-ai/claude-code";
import { readFileSync } from "fs";

const file = process.argv[2];
if (!file) { console.error("Usage: review.ts <file>"); process.exit(1); }

const code = readFileSync(file, "utf8");
const prompt = `Review this code for correctness, performance, and security.\n\n${code}`;

process.stdout.write(`Reviewing ${file}...\n\n`);

let cost = 0;
for await (const event of query({
  prompt,
  allowedTools: [],   // No tools needed — code is passed inline
  maxTurns: 1,        // Single-turn review
})) {
  if (event.type === "assistant") {
    for (const block of event.message.content) {
      if (block.type === "text") process.stdout.write(block.text);
    }
  }
  if (event.type === "result") {
    cost = event.cost_usd ?? 0;
  }
}

console.log(`\n\n[Cost: $${cost.toFixed(4)}]`);
